import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function Dashboard() {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('access');
    localStorage.removeItem('refresh');
    navigate('/login');
  };

  useEffect(() => {
    const fetchUser = async () => {
      const accessToken = localStorage.getItem('access');
      if (!accessToken) {
        navigate('/login');
        return;
      }

      try {
        const response = await axios.get('http://localhost:8000/api/user-info/', {
          headers: {
            Authorization: `Bearer ${accessToken}`,
          },
        });
        setUser(response.data);
      } catch (error) {
        console.error('Error fetching user info:', error);
        navigate('/login');
      }
    };

    fetchUser();
  }, [navigate]);

  if (!user) return <p className="text-center mt-5">Loading...</p>;

  return (
    <div className="container mt-5 text-center">
      <h2 className="mb-4">Welcome, {user.username} 👋</h2>
      <p className="lead">You are logged in as a <strong>{user.role}</strong>.</p>

      <div className="row justify-content-center mt-4">
        <div className="col-md-6">
          <div className="list-group">
            {user.role === 'teacher' && (
              <>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/students')}>Manage Students</button>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/teachers')}>Manage Teachers</button>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/grades')}>Enter Grades</button>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/attendance')}>Mark Attendance</button>
              </>
            )}

            {user.role === 'student' && (
              <>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/grades')}>View Grades</button>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/timetable')}>View Timetable</button>
                <button className="list-group-item list-group-item-action" onClick={() => navigate('/attendance')}>View Attendance</button>
              </>
            )}
          </div>
        </div>
      </div>

      <button className="btn btn-danger mt-4" onClick={handleLogout}>Logout</button>
    </div>
  );
}

export default Dashboard;
